// KEY CHANGES from v2:
// - Added check-in section (not just check-outs)
// - WhatsApp link per guest: wa.me/PHONE?text=Hola
// - Conserjería button at top: wa.me/+56923976934 with check-ins next 3 days
// - Color highlight for checkout-mañana
// - Phone numbers extracted from guestDetails

const allItems = $input.all().map(i => i.json);
let reservas;
if (allItems.length === 0) { reservas = []; }
else if (allItems.length === 1 && Array.isArray(allItems[0])) { reservas = allItems[0]; }
else { reservas = allItems; }

const meta = $('GetFechasYAlojamientos').first().json;
const alojArr = Array.isArray(meta.alojamientos) ? meta.alojamientos : [];

const listingMap = {};
for (const a of alojArr) {
  if (a.listing_id) listingMap[a.listing_id] = a.listing_name || a.listing_id;
}

// ── Helpers ──
const todayCLT = new Date(new Date().toLocaleString('en-US', {timeZone: 'America/Santiago'}));
const tomorrowCLT = new Date(todayCLT); tomorrowCLT.setDate(tomorrowCLT.getDate() + 1);
const getDateKey = (d) => d.toISOString().split('T')[0];
const todayKey = getDateKey(todayCLT);
const tomorrowKey = getDateKey(tomorrowCLT);
const in3DaysKey = getDateKey(new Date(todayCLT.getTime() + 3*86400000));

const normalizeYMD = (v) => {
  if (v === null || v === undefined) return null;
  const s = String(v);
  return s.length >= 10 ? s.slice(0, 10) : s;
};

const ddmmyyyy = (ymd) => {
  if (!ymd) return '';
  const parts = ymd.split('-');
  if (parts.length !== 3) return ymd;
  return `${parts[2]}-${parts[1]}-${parts[0]}`;
};

const toTitleCase = (s) =>
  String(s || '').replace(/\p{L}[\p{L}\p{Mn}]*/gu, (w) => w[0].toUpperCase() + w.slice(1));

const escapeHtml = (s) =>
  String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

// Extract phone from guest details
const getPhone = (r) => {
  const guests = r.guestsDetails?.list || [];
  for (const g of guests) {
    if (g.phone && g.phone.trim()) return g.phone.trim();
  }
  return '';
};

const getGuestName = (r) => {
  const guests = r.guestsDetails?.list || [];
  if (guests.length > 0 && guests[0].name) return guests[0].name;
  return '';
};

const waLink = (phone, text) => {
  if (!phone) return '';
  const clean = phone.replace(/[^0-9]/g, '');
  if (!clean) return '';
  const t = encodeURIComponent(text || 'Hola');
  return `https://wa.me/${clean}?text=${t}`;
};

// ── Build conserjería message ──
const conserjeNum = '56923976934';
let conserjeChecks = [];
for (const r of reservas) {
  const cin = normalizeYMD(r.checkInDate);
  if (!cin || cin > in3DaysKey) continue;
  const listingId = r._idlisting || '';
  const depto = listingMap[listingId] || listingId || '?';
  const guest = getGuestName(r);
  const guests = r.guests || 1;
  const cout = normalizeYMD(r.checkOutDate) || '';
  conserjeChecks.push(`depto ${depto} huesped ${guest}, pais Chile, huespedes ${guests}, checkout ${ddmmyyyy(cout)}`);
}

const conserjeMsg = conserjeChecks.length > 0
  ? `Hola Don David, informo check in: ${conserjeChecks.join(' | ')}`
  : 'Hola Don David, sin check-ins los proximos 3 dias';
const conserjeUrl = waLink(conserjeNum, conserjeMsg);

// ── Build sections ──
const checkinsHoy = reservas.filter(r => normalizeYMD(r.checkInDate) === todayKey);
const checkoutsHoy = reservas.filter(r => normalizeYMD(r.checkOutDate) === todayKey);
const checkoutsManana = reservas.filter(r => normalizeYMD(r.checkOutDate) === tomorrowKey);

let body = '';

// CONSERJERÍA BUTTON
body += `<div style="text-align:center;padding:16px;background:#1a2a3a;border-radius:12px;margin-bottom:16px">
  <a href="${conserjeUrl}" target="_blank" style="background:#25D366;color:white;padding:14px 28px;border-radius:8px;text-decoration:none;font-weight:bold;font-size:16px;display:inline-block">📋 Informar huespedes a conserjería</a>
  <div style="color:#8899aa;margin-top:8px;font-size:12px">Check-ins próximos 3 días</div>
</div>`;

// CHECK-IN TODAY
if (checkinsHoy.length > 0) {
  body += `<section style="background:#0d2818;border:1px solid #22c55e;border-radius:12px;padding:16px;margin-bottom:16px">
    <div style="font-size:18px;font-weight:bold;color:#22c55e;margin-bottom:12px">🟢 CHECK-IN HOY</div>`;
  for (const r of checkinsHoy) {
    const lid = r._idlisting || '';
    const depto = listingMap[lid] || lid || '?';
    const guest = getGuestName(r);
    const phone = getPhone(r);
    const cout = normalizeYMD(r.checkOutDate);
    const guests = r.guests || 1;
    body += `<div style="padding:8px;margin:4px 0;background:#0a1f12;border-radius:8px">
      <strong>Depto ${depto}</strong> · ${toTitleCase(guest)} · ${guests} pers · hasta ${ddmmyyyy(cout)}
      ${phone ? ` <a href="${waLink(phone,'Hola')}" target="_blank" style="color:#25D366;font-size:14px">📞 WhatsApp</a>` : ''}
    </div>`;
  }
  body += `</section>`;
}

// CHECK-OUT TODAY
if (checkoutsHoy.length > 0) {
  body += `<section style="background:#2a1010;border:1px solid #ef4444;border-radius:12px;padding:16px;margin-bottom:16px">
    <div style="font-size:18px;font-weight:bold;color:#ef4444;margin-bottom:12px">🔴 CHECK-OUT HOY (ASEO HOY)</div>`;
  for (const r of checkoutsHoy) {
    const lid = r._idlisting || '';
    const depto = listingMap[lid] || lid || '?';
    const guest = getGuestName(r);
    const phone = getPhone(r);
    const cin = normalizeYMD(r.checkInDate);
    body += `<div style="padding:8px;margin:4px 0;background:#1a0a0a;border-radius:8px">
      <strong>Depto ${depto}</strong> · ${toTitleCase(guest)} · Check-in: ${ddmmyyyy(cin)}
      ${phone ? ` <a href="${waLink(phone,'Hola')}" target="_blank" style="color:#25D366;font-size:14px">📞 WhatsApp</a>` : ''}
    </div>`;
  }
  body += `</section>`;
}

// CHECK-OUT TOMORROW (HIGHLIGHT)
if (checkoutsManana.length > 0) {
  body += `<section style="background:#332211;border:2px solid #f59e0b;border-radius:12px;padding:16px;margin-bottom:16px">
    <div style="font-size:18px;font-weight:bold;color:#f59e0b;margin-bottom:12px">🟠 ASEO MAÑANA ⚠️</div>`;
  for (const r of checkoutsManana) {
    const lid = r._idlisting || '';
    const depto = listingMap[lid] || lid || '?';
    const guest = getGuestName(r);
    const phone = getPhone(r);
    const cin = normalizeYMD(r.checkInDate);
    body += `<div style="padding:8px;margin:4px 0;background:#2a1a08;border-radius:8px">
      <strong>Depto ${depto}</strong> · ${toTitleCase(guest)} · desde ${ddmmyyyy(cin)}
      ${phone ? ` <a href="${waLink(phone,'Hola')}" target="_blank" style="color:#25D366;font-size:14px">📞 WhatsApp</a>` : ''}
    </div>`;
  }
  body += `</section>`;
}

// PROXIMOS 7 DIAS - remaining check-outs grouped by date
const remaining = reservas.filter(r => {
  const cout = normalizeYMD(r.checkOutDate);
  return cout && cout !== todayKey && cout !== tomorrowKey;
});

if (remaining.length > 0) {
  const grouped = new Map();
  for (const r of remaining) {
    const dia = normalizeYMD(r.checkOutDate);
    if (!dia) continue;
    if (!grouped.has(dia)) grouped.set(dia, []);
    grouped.get(dia).push(r);
  }

  body += `<section style="background:#0f1626;border:1px solid #223055;border-radius:12px;padding:16px">
    <div style="font-size:18px;font-weight:bold;color:#a9b6d6;margin-bottom:12px">🔵 PRÓXIMOS DÍAS</div>`;

  const dias = Array.from(grouped.keys()).sort();
  for (const dia of dias) {
    for (const r of grouped.get(dia)) {
      const lid = r._idlisting || '';
      const depto = listingMap[lid] || lid || '?';
      const guest = getGuestName(r);
      const phone = getPhone(r);
      const cin = normalizeYMD(r.checkInDate);
      body += `<div style="padding:6px;margin:2px 0;border-bottom:1px solid #1a2744">
        <strong>${ddmmyyyy(dia)}</strong> · Depto ${depto} · ${toTitleCase(guest)} · desde ${ddmmyyyy(cin)}
        ${phone ? ` <a href="${waLink(phone,'Hola')}" target="_blank" style="color:#25D366;font-size:12px">📞</a>` : ''}
      </div>`;
    }
  }
  body += `</section>`;
}

const html = `<!doctype html>
<html lang="es">
<head>
  <meta charset="utf-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <title>Aseos v3 · SandiegoApart</title>
  <style>
    :root{--bg:#0b0f19;--text:#e8eefc;--muted:#a9b6d6}
    body{margin:0;font-family:system-ui,sans-serif;background:var(--bg);color:var(--text);padding:16px}
    a{color:#25D366}
  </style>
</head>
<body>
  <h1 style="font-size:24px">🧹 Aseos · Reservas · SandiegoApart</h1>
  ${body}
  <div style="text-align:center;padding:16px;color:var(--muted);font-size:12px;margin-top:24px">
    Actualizado: ${new Date().toLocaleString('es-CL', {timeZone: 'America/Santiago'})} · Fuente: API Stays.net
  </div>
</body>
</html>`;

return [{ json: { html } }];
